+import org.openjdk.jmh.annotations.Param;
+import org.openjdk.jmh.annotations.Scope;
+import org.openjdk.jmh.annotations.Setup;
+import org.openjdk.jmh.annotations.State;
+import org.openjdk.jmh.annotations.Warmup;
+import org.openjdk.jmh.infra.Blackhole;
+
+@BenchmarkMode(Mode.AverageTime)
+@OutputTimeUnit(TimeUnit.NANOSECONDS)
+@Warmup(iterations = 5, time = 2)
+@Measurement(iterations = 7, time = 3)
+@Fork(3)
+public class JumpTableSwitch {
+
+  private static final int MASK = 1023;
+
+  @State(Scope.Thread)
+  public static class InputState {
+    private final int[] byteValues = new int[MASK + 1];
+    private final int[] dense04Values = new int[MASK + 1];
+    private final int[] dense08Values = new int[MASK + 1];
+    private final int[] dense09Values = new int[MASK + 1];
+    private final int[] dense10Values = new int[MASK + 1];
+    private final int[] dense12Values = new int[MASK + 1];
+    private final int[] dense16Values = new int[MASK + 1];
+    private final int[] dense24Values = new int[MASK + 1];
+    private final int[] dense32Values = new int[MASK + 1];
+    private final int[] dense64Values = new int[MASK + 1];
+    private final int[] dense72Values = new int[MASK + 1];
+    private final int[] dense80Values = new int[MASK + 1];
+    private final int[] dense96Values = new int[MASK + 1];
+    private final int[] dense112Values = new int[MASK + 1];
+    private final int[] dense120Values = new int[MASK + 1];
+    private final int[] dense128Values = new int[MASK + 1];
+    private final int[] dense256Values = new int[MASK + 1];
+    private final int[] dense512Values = new int[MASK + 1];
+    private final int[] dense1024Values = new int[MASK + 1];
+    private final int[] sparse08Step10Values = new int[MASK + 1];
+    private final int[] sparse08Step11Values = new int[MASK + 1];
+    private final int[] sparse16Step10Values = new int[MASK + 1];
+    private final int[] sparse16Step11Values = new int[MASK + 1];
+    private final int[] sparse32Step10Values = new int[MASK + 1];
+    private final int[] sparse32Step11Values = new int[MASK + 1];
+
+    @Param({"even", "defaultHeavy", "hotCase"})
+    public String distribution;
+
+    private int index;
+
+    @Setup
+    public void setup() {
+      int seed = 0x1234ABCD;
+      seed = fillDense(byteValues, 256, seed);
+      seed = fillDense(dense04Values, 4, seed);
+      seed = fillDense(dense08Values, 8, seed);
+      seed = fillDense(dense09Values, 9, seed);
+      seed = fillDense(dense10Values, 10, seed);
+      seed = fillDense(dense12Values, 12, seed);
+      seed = fillDense(dense16Values, 16, seed);
+      seed = fillDense(dense24Values, 24, seed);
+      seed = fillDense(dense32Values, 32, seed);
+      seed = fillDense(dense64Values, 64, seed);
+      seed = fillDense(dense72Values, 72, seed);
+      seed = fillDense(dense80Values, 80, seed);
+      seed = fillDense(dense96Values, 96, seed);
+      seed = fillDense(dense112Values, 112, seed);
+      seed = fillDense(dense120Values, 120, seed);
+      seed = fillDense(dense128Values, 128, seed);
+      seed = fillDense(dense256Values, 256, seed);
+      seed = fillDense(dense512Values, 512, seed);
+      seed = fillDense(dense1024Values, 1024, seed);
+      seed = fillSparse(sparse08Step10Values, 8, 10, seed);
+      seed = fillSparse(sparse08Step11Values, 8, 11, seed);
+      seed = fillSparse(sparse16Step10Values, 16, 10, seed);
+      seed = fillSparse(sparse16Step11Values, 16, 11, seed);
+      seed = fillSparse(sparse32Step10Values, 32, 10, seed);
+      seed = fillSparse(sparse32Step11Values, 32, 11, seed);
+      index = 0;
+    }
+
+    private int next(int[] values) {
+      int value = values[index];
+      index = (index + 1) & MASK;
+      return value;
+    }
+
+    private int fillDense(int[] values, int size, int seed) {
+      for (int i = 0; i < values.length; i++) {
+        seed = nextSeed(seed);
+        int value = Integer.remainderUnsigned(seed, size);
+        values[i] = switch (distribution) {
+          case "even" -> value;
+          case "defaultHeavy" -> ((seed & 3) == 0) ? value : size + value;
+          case "hotCase" -> ((seed & 3) == 0) ? value : 0;
+          default -> throw new IllegalStateException("unexpected distribution: " + distribution);
+        };
+      }
+      return seed;
+    }
+
+    private int fillSparse(int[] values, int cases, int step, int seed) {
+      for (int i = 0; i < values.length; i++) {
+        seed = nextSeed(seed);
+        int value = Integer.remainderUnsigned(seed, cases) * step;
+        values[i] = switch (distribution) {
+          case "even" -> value;
+          case "defaultHeavy" -> ((seed & 3) == 0) ? value : (cases + Integer.remainderUnsigned(seed, cases)) * step;
+          case "hotCase" -> ((seed & 3) == 0) ? value : 0;
+          default -> throw new IllegalStateException("unexpected distribution: " + distribution);
+        };
+      }
+      return seed;
+    }
+
+    private static int nextSeed(int seed) {
+      return seed * 1664525 + 1013904223;
+    }
+  }
+
+  @Benchmark
+  public void tableSwitchCase(InputState state, Blackhole blackhole) {
+    for (int i = 0; i < MASK; i++) {
+      blackhole.consume(tableSwitch(state.next(state.byteValues)));
+    }
+  }
+
+  @Benchmark
+  public void lookupSwitchCase(InputState state, Blackhole blackhole) {
+    for (int i = 0; i < MASK; i++) {
+      blackhole.consume(lookupSwitch(state.next(state.byteValues)));
+    }
+  }
+
+  @Benchmark
+  public void dense04SwitchCase(InputState state, Blackhole blackhole) {
+    for (int i = 0; i < MASK; i++) {
+      blackhole.consume(dense04Switch(state.next(state.dense04Values)));
+    }
+  }
+
+  @Benchmark
+  public void dense08SwitchCase(InputState state, Blackhole blackhole) {
+    for (int i = 0; i < MASK; i++) {
+      blackhole.consume(dense08Switch(state.next(state.dense08Values)));
+    }
+  }
+
+  @Benchmark
+  public void dense09SwitchCase(InputState state, Blackhole blackhole) {
+    for (int i = 0; i < MASK; i++) {
+      blackhole.consume(dense09Switch(state.next(state.dense09Values)));
+    }
+  }
+
+  @Benchmark
+  public void dense10SwitchCase(InputState state, Blackhole blackhole) {
+    for (int i = 0; i < MASK; i++) {
+      blackhole.consume(dense10Switch(state.next(state.dense10Values)));
+    }
+  }
+
+  @Benchmark
+  public void dense12SwitchCase(InputState state, Blackhole blackhole) {
+    for (int i = 0; i < MASK; i++) {
+      blackhole.consume(dense12Switch(state.next(state.dense12Values)));
+    }
+  }
